+#[test]
+fn connector_versions_sort_in_semver_order() -> Result<(), semver::Error> {
+    let mut actual = vec![
+        version("1.0.1")?,
+        version("2.0.0")?,
+        version("1.1.0")?,
+        version("1.0.0")?,
+        version("0.9.9")?,
+    ];
+    let expected = vec![
+        version("0.9.9")?,
+        version("1.0.0")?,
+        version("1.0.1")?,
+        version("1.1.0")?,
+        version("2.0.0")?,
+    ];
+
+    actual.sort();
+
+    assert_eq!(actual, expected);
+
+    Ok(())
+}
